#[wasm_bindgen_test]
fn use_platform_falls_back_to_web_platform_without_provider_on_wasm() {
    let outputs = Rc::new(RefCell::new(Vec::<String>::new()));

    fn app(outputs: Rc<RefCell<Vec<String>>>) -> Element {
        rsx! {
