1	//! SSR oracle tests for the Dioxus `ArsProvider` adapter.
2	//!
3	//! Covers spec §28 / §29 scenarios from
4	//! `spec/dioxus-components/utility/ars-provider.md`: `<div dir>` wrapper
5	//! rendering, direction inference vs. explicit override, provider-owned
6	//! auto-render of `ArsNonceStyle` when `style_strategy` is
7	//! `StyleStrategy::Nonce(...)`, and `dioxus_platform` default resolution via
8	//! feature flags. Browser DOM and reactive-update oracles live in the inline
9	//! `wasm_tests` module of `src/provider.rs` and in `tests/ars_provider_wasm.rs`.
10	
11	#![cfg(not(target_arch = "wasm32"))]
12	
13	use ars_core::{ColorMode, StyleStrategy};
14	use ars_dioxus::{ArsContext, ArsProvider, ArsProviderProps, default_dioxus_platform};
15	use ars_i18n::{Direction, Locale};
16	use dioxus::prelude::*;
17	
18	fn render_app(app: fn() -> Element) -> String {
19	    let mut vdom = VirtualDom::new(app);
20	
21	    vdom.rebuild_in_place();
22	
23	    dioxus_ssr::render(&vdom)
24	}
25	
26	#[test]
27	fn ars_provider_renders_ltr_wrapper_for_default_props() {
28	    fn app() -> Element {
29	        rsx! {
30	            ArsProvider {
31	                span { id: "child", "hello" }
32	            }
33	        }
34	    }
35	
36	    let html = render_app(app);
37	
38	    assert!(
39	        html.contains(r#"dir="ltr""#),
40	        "default provider should render dir=\"ltr\": {html}"
41	    );
42	    assert!(
43	        html.contains(r#"id="child""#),
44	        "children should render inside the provider wrapper: {html}"
45	    );
46	    assert!(
47	        !html.contains("<style nonce"),
48	        "default StyleStrategy::Inline must not emit a nonce style tag: {html}"
49	    );
50	}
51	
52	#[test]
53	fn ars_provider_infers_rtl_direction_from_rtl_locale() {
54	    fn app() -> Element {
55	        let locale = use_signal(|| Locale::parse("ar-SA").expect("locale should parse"));
56	
57	        rsx! {
58	            ArsProvider { locale,
59	                span { id: "child", "hello" }
60	            }
61	        }
62	    }
63	
64	    let html = render_app(app);
65	
66	    assert!(
67	        html.contains(r#"dir="rtl""#),
68	        "RTL locale should produce dir=\"rtl\": {html}"
69	    );
70	    assert!(
71	        html.contains(r#"id="child""#),
72	        "children should render inside the RTL wrapper: {html}"
73	    );
74	}
75	
76	#[test]
77	fn ars_provider_explicit_direction_overrides_locale_inferred_direction() {
78	    fn app() -> Element {
79	        let locale = use_signal(|| Locale::parse("ar-SA").expect("locale should parse"));
80	        let direction = use_signal(|| Direction::Ltr);
81	        rsx! {
82	            ArsProvider { locale, direction,
83	                span { id: "child", "hello" }
84	            }
85	        }
86	    }
87	
88	    let html = render_app(app);
89	
90	    assert!(
91	        html.contains(r#"dir="ltr""#),
92	        "explicit direction prop must override locale-inferred RTL: {html}"
93	    );
94	    assert!(
95	        !html.contains(r#"dir="rtl""#),
96	        "no rtl marker should remain after explicit override: {html}"
97	    );
98	}
99	
100	#[test]
101	fn ars_provider_with_nonce_style_strategy_emits_style_tag_with_nonce_attribute() {
102	    fn app() -> Element {
103	        rsx! {
104	            ArsProvider { style_strategy: StyleStrategy::Nonce(String::from("test-nonce")),
105	                span { id: "child", "hello" }
106	            }
107	        }
108	    }
109	
110	    let html = render_app(app);
111	
112	    assert!(
113	        html.contains(r#"<style nonce="test-nonce""#),
114	        "StyleStrategy::Nonce must auto-render <style nonce=...> tag: {html}"
115	    );
116	    assert!(
117	        html.contains(r#"id="child""#),
118	        "children must still render alongside the nonce style tag: {html}"
119	    );
120	}
121	
122	#[test]
123	fn ars_provider_with_inline_style_strategy_emits_no_nonce_style_tag() {
124	    fn app() -> Element {
125	        rsx! {
126	            ArsProvider { style_strategy: StyleStrategy::Inline,
127	                span { id: "child", "hello" }
128	            }
129	        }
130	    }
131	
132	    let html = render_app(app);
133	
134	    assert!(
135	        !html.contains("<style nonce"),
136	        "StyleStrategy::Inline must not emit a nonce style tag: {html}"
137	    );
138	}
139	
140	#[test]
141	fn ars_provider_with_cssom_style_strategy_emits_no_nonce_style_tag() {
142	    fn app() -> Element {
143	        rsx! {
144	            ArsProvider { style_strategy: StyleStrategy::Cssom,
145	                span { id: "child", "hello" }
146	            }
147	        }
148	    }
149	
150	    let html = render_app(app);
151	
152	    assert!(
153	        !html.contains("<style nonce"),
154	        "StyleStrategy::Cssom must not emit a nonce style tag: {html}"
155	    );
156	}
